import anthropic
import json
from datetime import datetime, timedelta

client = anthropic.Anthropic()

# User profile loaded from persistent memory store
USER_PROFILE = {
    "name": "Alex Rivera",
    "email": "alex@example.com",
    "timezone": "America/Los_Angeles",
    "communication_style": "direct, professional, minimal pleasantries",
    "common_contacts": {
        "sarah@acme.com": "Sarah Chen — VP Engineering, key stakeholder on Project Atlas",
        "james@partner.io": "James Liu — partnership contact, meet monthly",
    },
    "scheduling_constraints": "No meetings before 9am or after 5pm PT. Block 11am-12pm for deep work Mon/Wed/Fri.",
}

tools = [
    {
        "name": "read_email_thread",
        "description": "Fetch an email thread by subject keyword or sender. Returns the last N messages.",
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string", "description": "Subject keyword or sender email"},
                "max_messages": {"type": "integer", "default": 5},
            },
            "required": ["query"],
        },
    },
    {
        "name": "draft_email",
        "description": "Draft an email in the user's style. Returns draft only — does NOT send.",
        "input_schema": {
            "type": "object",
            "properties": {
                "to": {"type": "string"},
                "subject": {"type": "string"},
                "body": {"type": "string"},
                "in_reply_to_id": {"type": "string", "description": "Message ID if replying"},
            },
            "required": ["to", "subject", "body"],
        },
    },
    {
        "name": "check_calendar_availability",
        "description": "Check the user's calendar for free slots in a date range.",
        "input_schema": {
            "type": "object",
            "properties": {
                "start_date": {"type": "string", "description": "ISO 8601 date"},
                "end_date": {"type": "string", "description": "ISO 8601 date"},
                "duration_minutes": {"type": "integer"},
            },
            "required": ["start_date", "end_date", "duration_minutes"],
        },
    },
    {
        "name": "create_task",
        "description": "Create a task in the user's task manager with title, due date, and notes.",
        "input_schema": {
            "type": "object",
            "properties": {
                "title": {"type": "string"},
                "due_date": {"type": "string"},
                "notes": {"type": "string"},
            },
            "required": ["title"],
        },
    },
]

def stub_tool(name: str, args: dict) -> str:
    today = datetime.now().strftime("%Y-%m-%d")
    if name == "read_email_thread":
        return json.dumps([
            {"from": "sarah@acme.com", "date": today, "subject": "Atlas milestone delay",
             "body": "Hi Alex, the infra work pushed us back by 2 weeks. Can we discuss timeline?"},
        ])
    if name == "draft_email":
        return json.dumps({"draft_id": "draft_001", "preview": args.get("body", "")[:120]})
    if name == "check_calendar_availability":
        return json.dumps({"free_slots": ["2024-07-15T14:00", "2024-07-15T15:00", "2024-07-16T10:00"]})
    if name == "create_task":
        return json.dumps({"task_id": "task_042", "title": args["title"]})
    return "Unknown tool"

def run_personal_assistant(user_request: str) -> str:
    system = f"""You are Alex's personal assistant. Alex's profile:
{json.dumps(USER_PROFILE, indent=2)}

Rules:
- Draft emails in Alex's communication style (direct, professional, minimal pleasantries).
- Never send emails without explicitly surfacing the draft for review.
- For scheduling, respect the stated constraints.
- Create a follow-up task for any commitment Alex makes.
- Today's date: {datetime.now().strftime('%Y-%m-%d')}"""

    messages = [{"role": "user", "content": user_request}]

    while True:
        response = client.messages.create(
            model="claude-opus-4-5", max_tokens=2048,
            system=system, tools=tools, messages=messages,
        )
        if response.stop_reason == "end_turn":
            for b in response.content:
                if b.type == "text":
                    return b.text
            return "Done"
        if response.stop_reason == "tool_use":
            messages.append({"role": "assistant", "content": response.content})
            results = []
            for b in response.content:
                if b.type == "tool_use":
                    results.append({
                        "type": "tool_result",
                        "tool_use_id": b.id,
                        "content": stub_tool(b.name, b.input),
                    })
            messages.append({"role": "user", "content": results})

response = run_personal_assistant(
    "Sarah emailed about the Atlas milestone delay. Draft a reply apologising, "
    "propose we jump on a 30-minute call this week, and create a task to follow up "
    "if she doesn't respond by Friday."
)
print(response)
